import{_ as a,o as t,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"166. Meal Breaks","description":"","frontmatter":{"title":"166. Meal Breaks","eba":"Mental Health Services 2024-2028","topics":["hours","breaks","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/166-meal-breaks.md","filePath":"ebas/mental-health/support-services/preliminary/166-meal-breaks.md"}'),n={name:"ebas/mental-health/support-services/preliminary/166-meal-breaks.md"};function o(l,e,i,m,p,h){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_166-meal-breaks" tabindex="-1">166. Meal Breaks <a class="header-anchor" href="#_166-meal-breaks" aria-label="Permalink to &quot;166. Meal Breaks&quot;">​</a></h1><p><strong>166.1</strong> An Employee shall not be required to work more than 5 hours continuously without a meal interval of not less than 30 minutes and not more than 60 minutes.</p><p><strong>166.2</strong> Meal breaks shall not be regarded as time worked.</p><p><strong>166.3</strong> Night Duty</p><p><strong>(a)</strong> Employees who are not relieved from night duty (and on-call) during the rostered meal break shall be granted a meal break of not less than 20 minutes, to be commenced after completing three hours and not more than five hours of duty. Such meal break will be counted as time worked.</p><p><strong>(b)</strong> The arrangement in clause 166.3(a)[181.3(a)] may also be adopted in any case where there is mutual agreement between the Employer and Employee.</p>',6)])])}const c=a(n,[["render",o]]);export{u as __pageData,c as default};
